# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import Optional

def check_file_access(user_id: int, file_id: int, db_path: str) -> bool:
    """Check if user has permission to access the file"""
    try:
        conn = sqlite3.connect(db_path)
        cursor = conn.cursor()
        
        cursor.execute("""
            SELECT EXISTS(
                SELECT 1 FROM user_permissions 
                WHERE user_id = ? AND file_id = ? AND permission_level > 0
            )
        """, (user_id, file_id))
        
        result = cursor.fetchone()[0]
        conn.close()
        return bool(result)
    except Exception:
        return False

def read_file_contents(user_id: int, file_id: int, db_path: str, file_path: str) -> Optional[str]:
    """Check user permissions and return file contents if allowed"""
    if not check_file_access(user_id, file_id, db_path):
        return None
    
    try:
        with open(file_path, 'r', encoding='utf-8') as file:
            return file.read()
    except Exception:
        return None